    'name' => 'text_summarizer',
    'description' => 'Extractively summarize text by scoring sentences on word frequency and position. Returns the top N most important sentences, preserving original order. Pure function, no side effects.',
    'parameters' => 
    array (
      'type' => 'object',
      'properties' => 
      array (
