if (! function_exists('text_summarizer')) {
    function text_summarizer($text, $max_sentences = null, $min_sentence_length = null)
    {
        $maxSentences = $max_sentences ?? 3;
        $minSentenceLength = $min_sentence_length ?? 20;

        // Split into sentences (handles common English sentence endings)
        $sentences = preg_split('/(?<=[.!?])\s+/', $text);
        $sentences = array_filter($sentences, function($s) use ($minSentenceLength) {
            return strlen(trim($s)) >= $minSentenceLength;
        });
        $sentences = array_values($sentences);

        if (count($sentences) <= $maxSentences) {
            return [
                'summary' => implode(' ', $sentences),
                'sentence_count' => count($sentences),
                'original_count' => count($sentences),
                'method' => 'extractive',
            ];
        }

        // Build word frequency map (excluding common stop words)
        $stopWords = ['the','a','an','and','or','but','in','on','at','to','for','of','by','with','from',
            'is','are','was','were','be','been','being','have','has','had','do','does','did',
            'will','would','shall','should','may','might','can','could','its','it','this','that',
            'these','those','i','you','he','she','we','they','me','him','her','us','them',
            'my','your','his','its','our','their','not','no','nor','so','if','as'];

        $wordFreq = [];
        foreach ($sentences as $sentence) {
            $words = str_word_count(strtolower($sentence), 1);
            foreach ($words as $word) {
                if (!in_array($word, $stopWords)) {
                    $wordFreq[$word] = ($wordFreq[$word] ?? 0) + 1;
                }
            }
        }

        if (empty($wordFreq)) {
            // Fallback: return first N sentences
            return [
                'summary' => implode(' ', array_slice($sentences, 0, $maxSentences)),
                'sentence_count' => $maxSentences,
                'original_count' => count($sentences),
                'method' => 'extractive',
            ];
        }

        // Score each sentence: sum of word frequencies, weighted by position
        $totalSentences = count($sentences);
        $scores = [];
        foreach ($sentences as $i => $sentence) {
            $words = str_word_count(strtolower($sentence), 1);
            $score = 0;
            foreach ($words as $word) {
                if (isset($wordFreq[$word])) {
                    $score += $wordFreq[$word];
                }
            }
            // Normalize by sentence length
            $score = $score / max(1, count($words));
            // Position bonus: first and last sentences get a boost
            $positionWeight = 1.0;
            if ($i == 0) $positionWeight = 1.5;      // First sentence
            if ($i == $totalSentences - 1) $positionWeight = 1.2; // Last sentence
            $scores[] = ['index' => $i, 'score' => $score * $positionWeight];
        }

        // Sort by score descending and pick top N
        usort($scores, function($a, $b) { return $b['score'] <=> $a['score']; });
        $selected = array_slice($scores, 0, $maxSentences);

        // Sort selected by original order
        usort($selected, function($a, $b) { return $a['index'] <=> $b['index']; });

        $summaryParts = [];
        foreach ($selected as $s) {
            $summaryParts[] = $sentences[$s['index']];
        }

        return [
            'summary' => implode(' ', $summaryParts),
            'sentence_count' => count($summaryParts),
            'original_count' => count($sentences),
            'scores' => $scores,
            'method' => 'extractive',
        ];
    }
